import uuid
from typing import Dict, Literal

class Session:
    def __init__(self, session_id: str, timeout: int) -> None:
        self.session_id: str = session_id
        self.timeout: int = timeout
        self.status: Literal['active', 'closed'] = 'active'

class SessionManager:
    def __init__(self) -> None:
        self.sessions: Dict[str, Session] = {}

    def create_session(self, timeout: int) -> str:
        session_id: str = uuid.uuid4().hex
        new_session: Session = Session(session_id, timeout)
        self.sessions[session_id] = new_session
        return session_id

    def close_session(self, session_id: str) -> None:
        if session_id not in self.sessions:
            raise ValueError(f"Session {session_id} does not exist.")
        self.sessions[session_id].status = 'closed'

    def modify_session(self, session_id: str, new_timeout: int) -> None:
        if session_id not in self.sessions:
            raise ValueError(f"Session {session_id} does not exist.")
        self.sessions[session_id].timeout = new_timeout

    def get_session_status(self, session_id: str) -> Literal['active', 'closed']:
        if session_id not in self.sessions:
            raise ValueError(f"Session {session_id} does not exist.")
        return self.sessions[session_id].status

_manager: SessionManager = SessionManager()

def create_session(timeout: int) -> str:
    return _manager.create_session(timeout)

def close_session(session_id: str) -> None:
    _manager.close_session(session_id)

def modify_session(session_id: str, new_timeout: int) -> None:
    _manager.modify_session(session_id, new_timeout)

def get_session_status(session_id: str) -> Literal['active', 'closed']:
    return _manager.get_session_status(session_id)
