import java.util.*;

public class SmartHomeSystem {
    // Constants
    private static final String[] SUPPORTED_ROOMS = {"Living Room", "Kitchen", "Bedroom"};
    private static final int DEFAULT_BRIGHTNESS_LEVEL = 50;

    // Instance variables
    private final Map<String, Boolean> lightStatus = new HashMap<>();
    private final Map<String, Integer> brightnessLevels = new HashMap<>();
    private final List<String> commandHistory = new ArrayList<>();

    public SmartHomeSystem() {
        for (String room : SUPPORTED_ROOMS) {
            lightStatus.put(room, false);
            brightnessLevels.put(room, DEFAULT_BRIGHTNESS_LEVEL);
        }
    }

    public void turnOn(String room) {
        validateRoom(room);
        lightStatus.put(room, true);
        commandHistory.add("turnOn: " + room);
    }

    public void turnOff(String room) {
        validateRoom(room);
        lightStatus.put(room, false);
        commandHistory.add("turnOff: " + room);
    }

    public void adjustBrightness(String room, int level) {
        validateRoom(room);
        if (level < 0 || level > 100) {
            throw new IllegalArgumentException("Brightness level must be between 0 and 100");
        }
        brightnessLevels.put(room, level);
        commandHistory.add("adjustBrightness: " + room + " to " + level);
    }

    public String checkStatus(String room) {
        validateRoom(room);
        return String.format("Room: %s, Status: %s, Brightness: %d",
                room,
                lightStatus.get(room) ? "On" : "Off",
                brightnessLevels.get(room));
    }

    private void validateRoom(String room) {
        if (!Arrays.asList(SUPPORTED_ROOMS).contains(room)) {
            throw new IllegalArgumentException(String.format("Invalid room: %s. Supported rooms are: %s",
                    room, String.join(", ", SUPPORTED_ROOMS)));
        }
    }
}
