#include <iostream>
#include <map>
#include <string>
#include <sstream>

using namespace std;

class HardwareStore {
public:
    void ADD(const string& item_name, int quantity, double price) {
        inventory[item_name] = {quantity, price};
    }

    void REMOVE(const string& item_name) {
        auto it = inventory.find(item_name);
        if (it == inventory.end()) {
            cout << "Error: Item '" << item_name << "' not found." << endl;
        } else {
            inventory.erase(it);
        }
    }

    void UPDATE(const string& item_name, int new_quantity, double new_price) {
        auto it = inventory.find(item_name);
        if (it == inventory.end()) {
            cout << "Error: Item '" << item_name << "' not found." << endl;
        } else {
            it->second.quantity = new_quantity;
            it->second.price = new_price;
        }
    }

    void DISPLAY() {
        for (const auto& entry : inventory) {
            cout << "Item: " << entry.first 
                 << ", Quantity: " << entry.second.quantity 
                 << ", Price: " << entry.second.price << endl;
        }
    }

protected:

private:
    struct Item {
        int quantity = 0;
        double price = 0.0;
    };
    map<string, Item> inventory;
};

int main() {
    HardwareStore store;
    string line;
    while (getline(cin, line)) {
        istringstream iss(line);
        string command;
        iss >> command;
        if (command == "ADD") {
            string name;
            int qty;
            double price;
            if (iss >> name >> qty >> price) {
                store.ADD(name, qty, price);
            } else {
                cout << "Invalid ADD command. Usage: ADD item_name quantity price" << endl;
            }
        } else if (command == "REMOVE") {
            string name;
            if (iss >> name) {
                store.REMOVE(name);
            } else {
                cout << "Invalid REMOVE command. Usage: REMOVE item_name" << endl;
            }
        } else if (command == "UPDATE") {
            string name;
            int new_qty;
            double new_price;
            if (iss >> name >> new_qty >> new_price) {
                store.UPDATE(name, new_qty, new_price);
            } else {
                cout << "Invalid UPDATE command. Usage: UPDATE item_name new_quantity new_price" << endl;
            }
        } else if (command == "DISPLAY") {
            store.DISPLAY();
        } else {
            cout << "Invalid command." << endl;
        }
    }
    return 0;
}
