function processChartData(dataArray) {
    const groupedData = {};

    for (const dataPoint of dataArray) {
        const rawTimestamp = dataPoint.timestamp;
        const value = dataPoint.value;
        const timestamp = new Date(rawTimestamp);
        const hour = timestamp.getHours();

        if (!groupedData.hasOwnProperty(hour)) {
            groupedData[hour] = { sum: 0, count: 0 };
        }

        groupedData[hour].sum += value;
        groupedData[hour].count += 1;
    }

    const processedData = {};
    const hours = Object.keys(groupedData);

    for (const hour of hours) {
        const currentGroup = groupedData[hour];
        const average = currentGroup.sum / currentGroup.count;
        processedData[hour] = average;
    }

    return processedData;
}
