use std::collections::HashMap;

struct User {
    username: String,
    password: String,
}

struct System {
    users: HashMap<String, User>,
}

impl System {
    pub fn new() -> Self {
        System {
            users: HashMap::new(),
        }
    }

    pub fn register_user(&mut self, username: String, password: String) -> String {
        if self.users.contains_key(&username) {
            return "Username already exists".to_string();
        }
        self.users.insert(username.clone(), User { username, password });
        "Registered".to_string()
    }

    pub fn login_user(&self, username: String, password: String) -> String {
        match self.users.get(&username) {
            Some(user) if user.password == password => "Success".to_string(),
            _ => "Failure".to_string(),
        }
    }

    pub fn update_password(&mut self, username: String, old_password: String, new_password: String) -> String {
        match self.users.get_mut(&username) {
            Some(user) => {
                if user.password == old_password {
                    user.password = new_password;
                    "Updated".to_string()
                } else {
                    "Invalid".to_string()
                }
            }
            None => "Invalid".to_string()
        }
    }

    pub fn delete_user(&mut self, username: String) -> String {
        if self.users.remove(&username).is_some() {
            "Deleted".to_string()
        } else {
            "User not found".to_string()
        }
    }
}
