projects = {}

def add_project(name):
    if name in projects:
        print(f"Error: Project '{name}' already exists.")
    else:
        projects[name] = {'starts': [], 'stops': []}

def start_time(name, time_str):
    if name not in projects:
        print(f"Error: Project '{name}' does not exist.")
        return
    try:
        hours, mins = map(int, time_str.split(':'))
        if not (0 <= hours < 24 and 0 <= mins < 60):
            raise ValueError
        time_min = hours * 60 + mins
        projects[name]['starts'].append(time_min)
    except ValueError:
        print(f"Error: Invalid time format '{time_str}'. Use HH:MM.")

def stop_time(name, time_str):
    if name not in projects:
        print(f"Error: Project '{name}' does not exist.")
        return
    try:
        hours, mins = map(int, time_str.split(':'))
        if not (0 <= hours < 24 and 0 <= mins < 60):
            raise ValueError
        time_min = hours * 60 + mins
        projects[name]['stops'].append(time_min)
    except ValueError:
        print(f"Error: Invalid time format '{time_str}'. Use HH:MM.")

def report(name):
    if name not in projects:
        print(f"Error: Project '{name}' does not exist.")
        return
    starts = projects[name]['starts']
    stops = projects[name]['stops']
    total = 0
    for i in range(min(len(starts), len(stops))):
        start = starts[i]
        stop = stops[i]
        if stop < start:
            print(f"Warning: Stop time is before start time for interval {i+1} in project '{name}'. This interval will not be counted.")
            continue
        total += stop - start
    hours = total // 60
    minutes = total % 60
    print(f"Total time spent on project '{name}': {hours} hours and {minutes} minutes.")

while True:
    try:
        command = input().strip()
        if not command:
            continue
        parts = command.split()
        if parts[0] == 'ADD_PROJECT':
            if len(parts) != 2:
                print("Error: Invalid ADD_PROJECT command. Usage: ADD_PROJECT project_name")
                continue
            add_project(parts[1])
        elif parts[0] == 'START_TIME':
            if len(parts) != 3:
                print("Error: Invalid START_TIME command. Usage: START_TIME project_name time")
                continue
            start_time(parts[1], parts[2])
        elif parts[0] == 'STOP_TIME':
            if len(parts) != 3:
                print("Error: Invalid STOP_TIME command. Usage: STOP_TIME project_name time")
                continue
            stop_time(parts[1], parts[2])
        elif parts[0] == 'REPORT':
            if len(parts) != 2:
                print("Error: Invalid REPORT command. Usage: REPORT project_name")
                continue
            report(parts[1])
        else:
            print(f"Error: Unknown command '{parts[0]}'")
    except EOFError:
        break
