function manageTemperatureRecords() {
    const temperatureData = {};

    const getCurrentDate = () => {
        return new Date().toISOString().split('T')[0];
    };

    return {
        addRecord(location, temperature) {
            if (!temperatureData[location]) {
                temperatureData[location] = {};
            }
            const currentDate = getCurrentDate();
            temperatureData[location][currentDate] = temperature;
        },

        getAverage(location) {
            if (!temperatureData[location]) {
                return 'Error: Location not found.';
            }
            const records = Object.values(temperatureData[location]);
            if (records.length === 0) {
                return 'Error: No temperature records available for calculation.';
            }
            const sum = records.reduce((acc, temp) => acc + temp, 0);
            return sum / records.length;
        },

        removeRecord(location, date) {
            if (!temperatureData[location]) {
                return 'Error: Location not found.';
            }
            if (!temperatureData[location].hasOwnProperty(date)) {
                return 'Error: Date not found for the specified location.';
            }
            delete temperatureData[location][date];
            if (Object.keys(temperatureData[location]).length === 0) {
                delete temperatureData[location];
            }
        },

        updateRecord(location, date, newTemperature) {
            if (!temperatureData[location]) {
                return 'Error: Location not found.';
            }
            if (!temperatureData[location].hasOwnProperty(date)) {
                return 'Error: Date not found for the specified location.';
            }
            temperatureData[location][date] = newTemperature;
        }
    };
}
