use std::collections::HashMap;

pub struct FileSystem {
    files: HashMap<String, String>,
}

impl FileSystem {
    pub fn new() -> Self {
        FileSystem {
            files: HashMap::new(),
        }
    }

    pub fn create_file(&mut self, path: &str, content: &str) -> Result<(), String> {
        if self.files.contains_key(path) {
            Err(format!("File '{}' already exists", path))
        } else {
            self.files.insert(path.to_string(), content.to_string());
            Ok(())
        }
    }

    pub fn read_file(&self, path: &str) -> Result<&str, String> {
        self.files
            .get(path)
            .map(|s| s.as_str())
            .ok_or_else(|| format!("File '{}' not found", path))
    }

    pub fn update_file(&mut self, path: &str, new_content: &str) -> Result<(), String> {
        match self.files.get_mut(path) {
            Some(content) => {
                *content = new_content.to_string();
                Ok(())
            }
            None => Err(format!("File '{}' not found", path)),
        }
    }

    pub fn delete_file(&mut self, path: &str) -> Result<(), String> {
        if self.files.remove(path).is_none() {
            Err(format!("File '{}' not found", path))
        } else {
            Ok(())
        }
    }
}
