#include <stdio.h>
#include <stdlib.h>
#include <string.h>

struct Process {
    char name[100];
    int priority;
    struct Process* next;
};

void add_process(struct Process** head, const char* name, int priority) {
    struct Process* new_process;
    struct Process* current;
    struct Process* prev;

    new_process = (struct Process*)malloc(sizeof(struct Process));
    if (new_process == NULL) {
        return;
    }
    strncpy(new_process->name, name, sizeof(new_process->name) - 1);
    new_process->name[sizeof(new_process->name) - 1] = '\0';
    new_process->priority = priority;
    new_process->next = NULL;

    if (*head == NULL || (*head)->priority < priority) {
        new_process->next = *head;
        *head = new_process;
    } else {
        current = *head;
        prev = NULL;
        while (current != NULL && current->priority >= priority) {
            prev = current;
            current = current->next;
        }
        if (prev != NULL) {
            prev->next = new_process;
        }
        new_process->next = current;
    }
}

void kill_process(struct Process** head, const char* name) {
    struct Process* current;
    struct Process* prev;
    struct Process* temp;

    current = *head;
    prev = NULL;

    while (current != NULL) {
        if (strcmp(current->name, name) == 0) {
            if (prev == NULL) {
                *head = current->next;
                temp = current;
                current = current->next;
                free(temp);
            } else {
                prev->next = current->next;
                temp = current;
                current = current->next;
                free(temp);
            }
        } else {
            prev = current;
            current = current->next;
        }
    }
}

void kill_priority(struct Process** head, int priority) {
    struct Process* current;
    struct Process* prev;
    struct Process* temp;

    current = *head;
    prev = NULL;

    while (current != NULL) {
        if (current->priority == priority) {
            if (prev == NULL) {
                *head = current->next;
                temp = current;
                current = current->next;
                free(temp);
            } else {
                prev->next = current->next;
                temp = current;
                current = current->next;
                free(temp);
            }
        } else {
            prev = current;
            current = current->next;
        }
    }
}

void list_processes(struct Process* head) {
    struct Process* current;

    current = head;
    while (current != NULL) {
        printf("%s %d\n", current->name, current->priority);
        current = current->next;
    }
}

void free_list(struct Process* head) {
    struct Process* temp;

    while (head != NULL) {
        temp = head;
        head = head->next;
        free(temp);
    }
}

int main() {
    struct Process* head;
    char input[256];
    char* command;
    char* name;
    char* priority_str;
    int priority;

    head = NULL;

    while (fgets(input, sizeof(input), stdin) != NULL) {
        input[strcspn(input, "\n")] = '\0';
        command = strtok(input, " ");
        if (command == NULL) {
            continue;
        }

        if (strcmp(command, "ADD") == 0) {
            name = strtok(NULL, " ");
            priority_str = strtok(NULL, " ");
            if (name == NULL || priority_str == NULL) {
                continue;
            }
            priority = atoi(priority_str);
            add_process(&head, name, priority);
        } else if (strcmp(command, "KILL") == 0) {
            name = strtok(NULL, " ");
            if (name == NULL) {
                continue;
            }
            kill_process(&head, name);
        } else if (strcmp(command, "KILL_PRIORITY") == 0) {
            priority_str = strtok(NULL, " ");
            if (priority_str == NULL) {
                continue;
            }
            priority = atoi(priority_str);
            kill_priority(&head, priority);
        } else if (strcmp(command, "LIST") == 0) {
            list_processes(head);
        }
    }

    free_list(head);
    return 0;
}
