import javax.swing.*;
import java.awt.*;
import java.awt.event.*;

public class BasicCalculator extends JFrame {
    private JTextField firstNumberInput;
    private JTextField secondNumberInput;
    private JTextField resultOutput;
    private JButton addButton;
    private JButton subtractButton;
    private JButton multiplyButton;
    private JButton divideButton;

    public BasicCalculator() {
        initializeGUI();
    }

    private void initializeGUI() {
        setTitle("Basic Calculator");
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);
        setLayout(new GridLayout(5, 2));

        firstNumberInput = new JTextField();
        secondNumberInput = new JTextField();
        resultOutput = new JTextField();
        resultOutput.setEditable(false);

        addButton = new JButton("Add");
        subtractButton = new JButton("Subtract");
        multiplyButton = new JButton("Multiply");
        divideButton = new JButton("Divide");

        add(new JLabel("First Number:"));
        add(firstNumberInput);
        add(new JLabel("Second Number:"));
        add(secondNumberInput);
        add(new JLabel("Result:"));
        add(resultOutput);
        add(addButton);
        add(subtractButton);
        add(multiplyButton);
        add(divideButton);

        setupButtonListeners();
        pack();
        setSize(400, 300);
        setVisible(true);
    }

    private void setupButtonListeners() {
        addButton.addActionListener(e -> performOperation('+'));
        subtractButton.addActionListener(e -> performOperation('-'));
        multiplyButton.addActionListener(e -> performOperation('*'));
        divideButton.addActionListener(e -> performOperation('/'));
    }

    private void performOperation(char operator) {
        SwingUtilities.invokeLater(() -> {
            try {
                double num1 = Double.parseDouble(firstNumberInput.getText());
                double num2 = Double.parseDouble(secondNumberInput.getText());
                double result = 0;

                switch (operator) {
                    case '+':
                        result = add(num1, num2);
                        break;
                    case '-':
                        result = subtract(num1, num2);
                        break;
                    case '*':
                        result = multiply(num1, num2);
                        break;
                    case '/':
                        result = divide(num1, num2);
                        break;
                }
                resultOutput.setText(String.valueOf(result));
            } catch (NumberFormatException ex) {
                resultOutput.setText("Invalid input");
            }
        });
    }

    private double add(double a, double b) {
        return a + b;
    }

    private double subtract(double a, double b) {
        return a - b;
    }

    private double multiply(double a, double b) {
        return a * b;
    }

    private double divide(double a, double b) {
        return a / b;
    }

    public static void main(String[] args) {
        SwingUtilities.invokeLater(BasicCalculator::new);
    }
}
