use std::collections::HashMap;

/// Manages community center events.
pub struct EventManager {
    events: HashMap<String, String>,
}

impl EventManager {
    /// Creates a new EventManager instance.
    pub fn new() -> Self {
        EventManager {
            events: HashMap::new(),
        }
    }

    /// Adds a new event with the specified name and date.
    /// Returns an error if the event already exists.
    pub fn add_event(&mut self, name: String, date: String) -> Result<(), String> {
        if self.events.contains_key(&name) {
            Err(format!("Event '{}' already exists.", name))
        } else {
            self.events.insert(name, date);
            Ok(())
        }
    }

    /// Removes an event by its name.
    /// Returns an error if the event does not exist.
    pub fn remove_event(&mut self, name: String) -> Result<(), String> {
        if self.events.remove(&name).is_none() {
            Err(format!("Event '{}' not found.", name))
        } else {
            Ok(())
        }
    }

    /// Retrieves the date of an event by its name.
    /// Returns `None` if the event does not exist.
    pub fn get_event(&self, name: String) -> Option<String> {
        self.events.get(&name).cloned()
    }

    /// Returns a list of all event names currently registered.
    pub fn list_events(&self) -> Vec<String> {
        self.events.keys().cloned().collect()
    }
}
