```typescript
type Task = {
    task_id: number;
    description: string;
    completed: boolean;
};

const manageTodos: (command: 'add' | 'complete' | 'delete' | 'list', ...args: any[]) => string | undefined | Task[] = (() => {
    const tasks: Task[] = [];
    let nextId: number = 1;

    return (command: 'add' | 'complete' | 'delete' | 'list', ...args: any[]): string | undefined | Task[] => {
        switch (command) {
            case 'add': {
                const description: string = args[0];
                tasks.push({ task_id: nextId++, description: description, completed: false });
                return undefined;
            }
            case 'complete': {
                const taskId: number = args[0];
                const task: Task | undefined = tasks.find((t: Task) => t.task_id === taskId);
                if (!task) return `Error: Task with ID ${taskId} does not exist.`;
                task.completed = true;
                return undefined;
            }
            case 'delete': {
                const taskId: number = args[0];
                const index: number = tasks.findIndex((t: Task) => t.task_id === taskId);
                if (index === -1) return `Error: Task with ID ${taskId} does not exist.`;
                tasks.splice(index, 1);
                return undefined;
            }
            case 'list': {
                return tasks.map((task: Task) => ({ ...task }));
            }
            default: {
                const unexpectedCommand: never = command;
                throw new Error(`Unexpected command: ${unexpectedCommand}`);
            }
