#include <stdio.h>
#include <string.h>
#include <stdlib.h>

#define MAX_NAME_LEN 50
#define MAX_VALUE_LEN 100
#define MAX_SETTINGS 100

struct Setting {
    char name[MAX_NAME_LEN];
    char value[MAX_VALUE_LEN];
    char default_value[MAX_VALUE_LEN];
};

const char* manage_settings(const char* command) {
    static struct Setting settings[MAX_SETTINGS];
    static int count = 0;
    char cmd[10];
    char setting_name[MAX_NAME_LEN];
    char setting_value[MAX_VALUE_LEN];
    static char output_buffer[1024];
    int i;
    int found;

    sscanf(command, "%s", cmd);

    if (strcmp(cmd, "SET") == 0) {
        sscanf(command, "%*s %s %s", setting_name, setting_value);
        found = 0;
        for (i = 0; i < count; i++) {
            if (strcmp(settings[i].name, setting_name) == 0) {
                strcpy(settings[i].value, setting_value);
                found = 1;
                break;
            }
        }
        if (!found && count < MAX_SETTINGS) {
            strcpy(settings[count].name, setting_name);
            strcpy(settings[count].value, setting_value);
            strcpy(settings[count].default_value, setting_value);
            count++;
        }
        return "";
    } else if (strcmp(cmd, "GET") == 0) {
        sscanf(command, "%*s %s", setting_name);
        for (i = 0; i < count; i++) {
            if (strcmp(settings[i].name, setting_name) == 0) {
                return settings[i].value;
            }
        }
        return "Setting not found";
    } else if (strcmp(cmd, "RESET") == 0) {
        sscanf(command, "%*s %s", setting_name);
        found = 0;
        for (i = 0; i < count; i++) {
            if (strcmp(settings[i].name, setting_name) == 0) {
                strcpy(settings[i].value, settings[i].default_value);
                found = 1;
                break;
            }
        }
        return found ? "" : "Setting not found";
    } else if (strcmp(cmd, "LIST_ALL") == 0) {
        output_buffer[0] = '\0';
        for (i = 0; i < count; i++) {
            strcat(output_buffer, settings[i].name);
            strcat(output_buffer, "=");
            strcat(output_buffer, settings[i].value);
            strcat(output_buffer, "\n");
        }
        return output_buffer;
    } else {
        return "Invalid command";
    }
}
