#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <pthread.h>
#include <unistd.h>
#include <errno.h>

typedef enum { WAITING, RUNNING, COMPLETED, CANCELED } TaskState;

typedef struct Task {
    char name[256];
    int duration;
    TaskState state;
    pthread_t thread;
    int cancel_requested;
    struct Task *next;
} Task;

pthread_mutex_t task_list_mutex = PTHREAD_MUTEX_INITIALIZER;
Task *task_list = NULL;

void *task_thread(void *arg) {
    Task *task = (Task *)arg;
    int time_remaining = task->duration;

    while (time_remaining > 0) {
        sleep(1);
        time_remaining--;

        pthread_mutex_lock(&task_list_mutex);
        if (task->cancel_requested) {
            task->state = CANCELED;
            pthread_mutex_unlock(&task_list_mutex);
            return NULL;
        }
        pthread_mutex_unlock(&task_list_mutex);
    }

    pthread_mutex_lock(&task_list_mutex);
    task->state = COMPLETED;
    pthread_mutex_unlock(&task_list_mutex);

    return NULL;
}

Task *find_task(const char *name) {
    Task *current = task_list;
    while (current != NULL) {
        if (strcmp(current->name, name) == 0) return current;
        current = current->next;
    }
    return NULL;
}

void add_task(const char *name, int duration) {
    pthread_mutex_lock(&task_list_mutex);
    if (find_task(name) != NULL) {
        printf("Error: Task '%s' already exists.\n", name);
        pthread_mutex_unlock(&task_list_mutex);
        return;
    }

    Task *new_task = malloc(sizeof(Task));
    strcpy(new_task->name, name);
    new_task->duration = duration;
    new_task->state = WAITING;
    new_task->cancel_requested = 0;
    new_task->next = task_list;
    task_list = new_task;
    pthread_mutex_unlock(&task_list_mutex);
    printf("Task '%s' added.\n", name);
}

void start_task(const char *name) {
    pthread_mutex_lock(&task_list_mutex);
    Task *task = find_task(name);
    if (task == NULL) {
        printf("Error: Task '%s' not found.\n", name);
        pthread_mutex_unlock(&task_list_mutex);
        return;
    }
    if (task->state != WAITING) {
        printf("Error: Task '%s' not in waiting state.\n", name);
        pthread_mutex_unlock(&task_list_mutex);
        return;
    }

    task->state = RUNNING;
    if (pthread_create(&task->thread, NULL, task_thread, task) != 0) {
        perror("Thread creation failed");
        task->state = WAITING;
    }
    pthread_mutex_unlock(&task_list_mutex);
}

void check_task(const char *name) {
    pthread_mutex_lock(&task_list_mutex);
    Task *task = find_task(name);
    if (task == NULL) {
        printf("Error: Task '%s' not found.\n", name);
        pthread_mutex_unlock(&task_list_mutex);
        return;
    }

    const char *states[] = {"waiting", "running", "completed", "canceled"};
    printf("Task '%s' is %s.\n", name, states[task->state]);
    pthread_mutex_unlock(&task_list_mutex);
}

void cancel_task(const char *name) {
    pthread_mutex_lock(&task_list_mutex);
    Task *task = find_task(name);
    if (task == NULL) {
        printf("Error: Task '%s' not found.\n", name);
        pthread_mutex_unlock(&task_list_mutex);
        return;
    }

    if (task->state == WAITING) {
        task->state = CANCELED;
        printf("Task '%s' canceled.\n", name);
    } else if (task->state == RUNNING) {
        task->cancel_requested = 1;
        printf("Task '%s' cancellation initiated.\n", name);
    } else {
        printf("Error: Task '%s' cannot be canceled.\n", name);
    }
    pthread_mutex_unlock(&task_list_mutex);
}

int main() {
    char input[256];
    while (fgets(input, sizeof(input), stdin)) {
        input[strcspn(input, "\n")] = '\0';
        char *cmd = strtok(input, " ");

        if (cmd == NULL) continue;

        if (strcmp(cmd, "ADD_TASK") == 0) {
            char *name = strtok(NULL, " ");
            char *dur = strtok(NULL, " ");
            if (!name || !dur) {
                printf("Invalid ADD_TASK command\n");
                continue;
            }
            add_task(name, atoi(dur));
        } else if (strcmp(cmd, "START_TASK") == 0) {
            char *name = strtok(NULL, " ");
            if (!name) {
                printf("Invalid START_TASK command\n");
                continue;
            }
            start_task(name);
        } else if (strcmp(cmd, "CHECK_TASK") == 0) {
            char *name = strtok(NULL, " ");
            if (!name) {
                printf("Invalid CHECK_TASK command\n");
                continue;
            }
            check_task(name);
        } else if (strcmp(cmd, "CANCEL_TASK") == 0) {
            char *name = strtok(NULL, " ");
            if (!name) {
                printf("Invalid CANCEL_TASK command\n");
                continue;
            }
            cancel_task(name);
        } else {
            printf("Unknown command: %s\n", cmd);
        }
    }
    return 0;
}
