#include <fstream>
#include <string>
#include <iostream>

class FileManager {
public:
    void openFile(std::string fileName);
    void writeFile(std::string data);
    std::string readFile();
    void closeFile();

protected:

private:
    std::fstream fileStream;
    std::string currentFileName;
};

void FileManager::openFile(std::string fileName) {
    if (fileStream.is_open()) {
        fileStream.close();
    }

    std::ifstream checkFile(fileName);
    if (!checkFile) {
        std::cerr << "Error: File " << fileName << " does not exist." << std::endl;
        return;
    }
    checkFile.close();

    fileStream.open(fileName, std::ios::in | std::ios::out | std::ios::app);
    if (!fileStream) {
        std::cerr << "Error: Unable to open file " << fileName << "." << std::endl;
        return;
    }

    currentFileName = fileName;
}

void FileManager::writeFile(std::string data) {
    if (!fileStream.is_open()) {
        std::cerr << "Error: No file is currently open." << std::endl;
        return;
    }

    fileStream << data;
}

std::string FileManager::readFile() {
    if (!fileStream.is_open()) {
        std::cerr << "Error: No file is currently open." << std::endl;
        return "";
    }

    std::streampos originalPos = fileStream.tellg();
    fileStream.seekg(0, std::ios::beg);

    std::string content((std::istreambuf_iterator<char>(fileStream)), std::istreambuf_iterator<char>());

    fileStream.seekg(originalPos);
    return content;
}

void FileManager::closeFile() {
    if (fileStream.is_open()) {
        fileStream.close();
        currentFileName.clear();
    } else {
        std::cerr << "Error: No file is currently open." << std::endl;
    }
}
