class schedule_appointment:
    def __init__(self) -> None:
        self.appointments: list[dict] = []
        self.next_id: int = 1

    def book_appointment(self, date: str, time: str, doctor_id: int) -> bool:
        for appointment in self.appointments:
            if (appointment["date"] == date and appointment["time"] == time and appointment["doctor_id"] == doctor_id):
                return False
        new_appointment = {
            "appointment_id": self.next_id,
            "date": date,
            "time": time,
            "doctor_id": doctor_id
        }
        self.appointments.append(new_appointment)
        self.next_id += 1
        return True

    def cancel_appointment(self, appointment_id: int) -> bool:
        for index, appointment in enumerate(self.appointments):
            if appointment["appointment_id"] == appointment_id:
                self.appointments.pop(index)
                return True
        return False

    def reschedule_appointment(self, appointment_id: int, new_date: str, new_time: str) -> bool:
        target_appointment = None
        for appointment in self.appointments:
            if appointment["appointment_id"] == appointment_id:
                target_appointment = appointment
                break
        if not target_appointment:
            return False
        doctor_id = target_appointment["doctor_id"]
        for appointment in self.appointments:
            if (appointment["appointment_id"] != appointment_id and appointment["doctor_id"] == doctor_id
                    and appointment["date"] == new_date and appointment["time"] == new_time):
                return False
        target_appointment["date"] = new_date
        target_appointment["time"] = new_time
        return True
