function manageShoppingCart() {
    const cart = {};

    return {
        /**
         * Adds a product with a specified quantity to the shopping cart.
         * @param {string} productId - The ID of the product to add.
         * @param {number} quantity - The quantity to add.
         */
        addProduct: function(productId, quantity) {
            let existingQuantity;
            if (cart.hasOwnProperty(productId)) {
                existingQuantity = cart[productId];
                cart[productId] = existingQuantity + quantity;
            } else {
                cart[productId] = quantity;
            }
        },

        /**
         * Removes a product from the shopping cart.
         * @param {string} productId - The ID of the product to remove.
         * @returns {string|undefined} Error message if product not found.
         */
        removeProduct: function(productId) {
            let exists;
            exists = cart.hasOwnProperty(productId);
            if (!exists) {
                return 'Product not found';
            }
            delete cart[productId];
        },

        /**
         * Updates the quantity of a specific product in the shopping cart.
         * @param {string} productId - The ID of the product to update.
         * @param {number} quantity - The new quantity.
         * @returns {string|undefined} Error message if product not found.
         */
        updateProduct: function(productId, quantity) {
            let exists;
            exists = cart.hasOwnProperty(productId);
            if (!exists) {
                return 'Product not found';
            }
            cart[productId] = quantity;
        },

        /**
         * Retrieves the quantity of a product in the shopping cart.
         * @param {string} productId - The ID of the product to retrieve.
         * @returns {number|string} The quantity or an error message if not found.
         */
        getProduct: function(productId) {
            let exists, quantity;
            exists = cart.hasOwnProperty(productId);
            if (!exists) {
                return 'Product not found';
            }
            quantity = cart[productId];
            return quantity;
        }
    };
}
