#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <sys/sysinfo.h>
#include <sys/statvfs.h>

#define PORT 8080

double get_cpu_usage() {
    unsigned long user, nice, system, idle, iowait, total1, total2, idle1, idle2;
    FILE* file = fopen("/proc/stat", "r");
    if (!file) return -1.0;
    fscanf(file, "cpu %lu %lu %lu %lu %lu %*lu %*lu %*lu %*lu %*lu", &user, &nice, &system, &idle, &iowait);
    fclose(file);
    idle1 = idle + iowait;
    total1 = user + nice + system + idle + iowait;
    sleep(1);
    file = fopen("/proc/stat", "r");
    if (!file) return -1.0;
    fscanf(file, "cpu %lu %lu %lu %lu %lu %*lu %*lu %*lu %*lu %*lu", &user, &nice, &system, &idle, &iowait);
    fclose(file);
    idle2 = idle + iowait;
    total2 = user + nice + system + idle + iowait;
    double delta_total = total2 - total1;
    double delta_idle = idle2 - idle1;
    return delta_total ? (1.0 - delta_idle / delta_total) * 100.0 : 0.0;
}

double get_memory_usage() {
    struct sysinfo info;
    if (sysinfo(&info) != 0) return -1.0;
    unsigned long total = info.totalram * info.mem_unit;
    unsigned long free = info.freeram * info.mem_unit;
    return (total - free) * 100.0 / total;
}

double get_disk_usage() {
    struct statvfs vfs;
    if (statvfs("/", &vfs) != 0) return -1.0;
    unsigned long total = vfs.f_blocks * vfs.f_frsize;
    unsigned long free = vfs.f_bavail * vfs.f_frsize;
    return (total - free) * 100.0 / total;
}

void handle_client(int client_socket) {
    char buffer[1024] = {0};
    ssize_t bytes_read = read(client_socket, buffer, 1024);
    if (bytes_read <= 0) return;
    buffer[bytes_read] = '\0';
    double result = -1.0;
    if (strcmp(buffer, "CPU_USAGE") == 0) result = get_cpu_usage();
    else if (strcmp(buffer, "MEMORY_USAGE") == 0) result = get_memory_usage();
    else if (strcmp(buffer, "DISK_USAGE") == 0) result = get_disk_usage();
    char response[32];
    snprintf(response, sizeof(response), "%.2f", result);
    send(client_socket, response, strlen(response), 0);
}

int main() {
    int server_fd;
    struct sockaddr_in address;
    int opt = 1;
    server_fd = socket(AF_INET, SOCK_STREAM, 0);
    setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR | SO_REUSEPORT, &opt, sizeof(opt));
    address.sin_family = AF_INET;
    address.sin_addr.s_addr = INADDR_ANY;
    address.sin_port = htons(PORT);
    bind(server_fd, (struct sockaddr*)&address, sizeof(address));
    listen(server_fd, 3);
    while (1) {
        int client_socket = accept(server_fd, NULL, NULL);
        if (client_socket < 0) continue;
        handle_client(client_socket);
        close(client_socket);
    }
}
