    Playlist() : currentIndex(0) {}

    void addSong(const string& name) {
        lock_guard<mutex> lock(mtx);
        songs.push_back(name);
    }

    void removeSong(const string& name) {
        lock_guard<mutex> lock(mtx);
        auto it = find(songs.begin(), songs.end(), name);
        if (it == songs.end()) {
            cout << "Song not found: " << name << endl;
            return;
        }
        songs.erase(it);
        if (songs.empty()) {
            currentIndex = 0;
        } else {
            currentIndex = min(currentIndex, songs.size() - 1);
        }
    }

    void play() {
        lock_guard<mutex> lock(mtx);
        if (songs.empty()) {
            cout << "Playlist is empty." << endl;
            return;
        }
        if (currentIndex >= songs.size()) {
            currentIndex = 0;
        }
        cout << "Playing: " << songs[currentIndex] << endl;
        currentIndex++;
    }

    void list() {
        lock_guard<mutex> lock(mtx);
        if (songs.empty()) {
            cout << "Playlist is empty." << endl;
            return;
        }
        cout << "Playlist:" << endl;
        for (size_t i = 0; i < songs.size(); ++i) {
            cout << i + 1 << ". " << songs[i] << endl;
        }
    }
};

