use std::collections::HashMap;
use std::io::{BufRead, BufReader, Write};
use std::net::{TcpListener, TcpStream};
use std::sync::{Arc, Mutex};
use std::sync::mpsc::{self, Sender};
use std::thread;

type SharedState = Arc<Mutex<HashMap<String, Sender<String>>>>;

fn main() -> std::io::Result<()> {
    let listener = TcpListener::bind("127.0.0.1:8080")?;
    let shared_state: SharedState = Arc::new(Mutex::new(HashMap::new()));

    for stream in listener.incoming() {
        let stream = stream?;
        let shared = shared_state.clone();
        thread::spawn(move || {
            handle_client(stream, shared).unwrap_or_else(|e| eprintln!("Error: {}", e));
        });
    }
    Ok(())
}

fn handle_client(stream: TcpStream, shared: SharedState) -> std::io::Result<()> {
    let (reader, writer) = (stream.try_clone()?, stream);
    let (tx, rx) = mpsc::channel::<String>();

    let writer_thread = thread::spawn(move || {
        let mut writer = writer;
        for msg in rx {
            if let Err(e) = writeln!(writer, "{}", msg) {
                eprintln!("Write error: {}", e);
                break;
            }
        }
    });

    let mut reader = BufReader::new(reader);
    let mut current_user: Option<String> = None;

    loop {
        let mut line = String::new();
        if reader.read_line(&mut line)? == 0 {
            break;
        }
        let line = line.trim();
        let parts: Vec<&str> = line.splitn(2, ' ').collect();

        match parts[0] {
            "JOIN" => {
                if parts.len() < 2 {
                    let _ = tx.send("ERROR: Username required".to_string());
                    continue;
                }
                let username = parts[1].to_string();
                let mut users = shared.lock().unwrap();
                if users.contains_key(&username) {
                    let _ = tx.send("ERROR: Username taken".to_string());
                } else {
                    users.insert(username.clone(), tx.clone());
                    current_user = Some(username.clone());
                    let msg = format!("{} has joined the chat.", username);
                    drop(users);
                    broadcast(&shared, &msg);
                }
            }
            "LEAVE" => {
                if let Some(username) = current_user.take() {
                    let mut users = shared.lock().unwrap();
                    users.remove(&username);
                    let msg = format!("{} has left the chat.", username);
                    drop(users);
                    broadcast(&shared, &msg);
                }
            }
            "MESSAGE" => {
                if parts.len() < 2 {
                    let _ = tx.send("ERROR: Message required".to_string());
                    continue;
                }
                if let Some(username) = &current_user {
                    let text = parts[1].to_string();
                    let msg = format!("{}: {}", username, text);
                    broadcast(&shared, &msg);
                } else {
                    let _ = tx.send("ERROR: Not joined".to_string());
                }
            }
            "LIST" => {
                let users = shared.lock().unwrap();
                let user_list = users.keys().cloned().collect::<Vec<_>>().join(", ");
                let _ = tx.send(format!("Connected users: {}", user_list));
            }
            _ => {
                let _ = tx.send("ERROR: Unknown command".to_string());
            }
        }
    }

    if let Some(username) = current_user {
        let mut users = shared.lock().unwrap();
        users.remove(&username);
        let msg = format!("{} has left the chat.", username);
        drop(users);
        broadcast(&shared, &msg);
    }

    drop(tx);
    let _ = writer_thread.join();
    Ok(())
}

fn broadcast(shared: &SharedState, msg: &str) {
    let users = shared.lock().unwrap();
    for tx in users.values() {
        let _ = tx.send(msg.to_string());
    }
}
