#include <stdio.h>
#include <stdlib.h>

typedef struct {
    int customerId;
    double balance;
} Account;

typedef struct {
    Account *accounts;
    size_t count;
    size_t capacity;
} AccountCollection;

static AccountCollection bank = {NULL, 0, 0};

typedef enum {
    SUCCESS,
    ERROR_CUSTOMER_ID_NOT_FOUND,
    ERROR_INSUFFICIENT_BALANCE,
    ERROR_DUPLICATE_CUSTOMER_ID,
    ERROR_INVALID_AMOUNT,
    ERROR_MEMORY_ALLOCATION_FAILED
} BankError;

int createAccount(int customerId, double initialBalance) {
    if (initialBalance < 0) {
        fprintf(stderr, "Error: Initial balance cannot be negative.\n");
        return ERROR_INVALID_AMOUNT;
    }
    for (size_t i = 0; i < bank.count; ++i) {
        if (bank.accounts[i].customerId == customerId) {
            fprintf(stderr, "Error: Customer ID %d already exists.\n", customerId);
            return ERROR_DUPLICATE_CUSTOMER_ID;
        }
    }
    if (bank.count >= bank.capacity) {
        size_t newCapacity = bank.capacity == 0 ? 1 : bank.capacity * 2;
        Account *newAccounts = realloc(bank.accounts, newCapacity * sizeof(Account));
        if (!newAccounts) {
            fprintf(stderr, "Error: Memory allocation failed.\n");
            return ERROR_MEMORY_ALLOCATION_FAILED;
        }
        bank.accounts = newAccounts;
        bank.capacity = newCapacity;
    }
    bank.accounts[bank.count].customerId = customerId;
    bank.accounts[bank.count].balance = initialBalance;
    bank.count++;
    return SUCCESS;
}

int deposit(int customerId, double amount) {
    if (amount <= 0) {
        fprintf(stderr, "Error: Invalid deposit amount.\n");
        return ERROR_INVALID_AMOUNT;
    }
    for (size_t i = 0; i < bank.count; ++i) {
        if (bank.accounts[i].customerId == customerId) {
            bank.accounts[i].balance += amount;
            return SUCCESS;
        }
    }
    fprintf(stderr, "Error: Customer ID %d not found.\n", customerId);
    return ERROR_CUSTOMER_ID_NOT_FOUND;
}

int withdraw(int customerId, double amount) {
    if (amount <= 0) {
        fprintf(stderr, "Error: Invalid withdrawal amount.\n");
        return ERROR_INVALID_AMOUNT;
    }
    for (size_t i = 0; i < bank.count; ++i) {
        if (bank.accounts[i].customerId == customerId) {
            if (bank.accounts[i].balance < amount) {
                fprintf(stderr, "Error: Insufficient balance for withdrawal.\n");
                return ERROR_INSUFFICIENT_BALANCE;
            }
            bank.accounts[i].balance -= amount;
            return SUCCESS;
        }
    }
    fprintf(stderr, "Error: Customer ID %d not found.\n", customerId);
    return ERROR_CUSTOMER_ID_NOT_FOUND;
}

double getBalance(int customerId) {
    for (size_t i = 0; i < bank.count; ++i) {
        if (bank.accounts[i].customerId == customerId) {
            return bank.accounts[i].balance;
        }
    }
    fprintf(stderr, "Error: Customer ID %d not found.\n", customerId);
    return -1.0;
}

int closeAccount(int customerId) {
    for (size_t i = 0; i < bank.count; ++i) {
        if (bank.accounts[i].customerId == customerId) {
            for (size_t j = i; j < bank.count - 1; ++j) {
                bank.accounts[j] = bank.accounts[j + 1];
            }
            bank.count--;
            return SUCCESS;
        }
    }
    fprintf(stderr, "Error: Customer ID %d not found.\n", customerId);
    return ERROR_CUSTOMER_ID_NOT_FOUND;
}
