use std::io::{self, Write};

const MAX_STUDENTS: usize = 100;

struct Student {
    name: String,
    present: bool,
}

struct AttendanceList {
    students: Vec<Student>,
}

impl AttendanceList {
    fn new() -> Self {
        AttendanceList { students: Vec::new() }
    }

    fn add(&mut self, name: String) -> Result<(), String> {
        if self.students.len() >= MAX_STUDENTS {
            return Err(format!("Maximum capacity of {} students reached.", MAX_STUDENTS));
        }
        if self.students.iter().any(|s| s.name == name) {
            return Err(format!("Student '{}' already exists.", name));
        }
        self.students.push(Student { name, present: false });
        Ok(())
    }

    fn remove(&mut self, name: &str) -> Result<(), String> {
        let index = self.students.iter().position(|s| s.name == name)
            .ok_or_else(|| format!("Student '{}' not found.", name))?;
        self.students.remove(index);
        Ok(())
    }

    fn check_in(&mut self, name: &str) -> Result<(), String> {
        let student = self.students.iter_mut().find(|s| s.name == name)
            .ok_or_else(|| format!("Student '{}' not found.", name))?;
        student.present = true;
        Ok(())
    }

    fn report(&self) {
        println!("Attendance Report:");
        for student in &self.students {
            println!("- {}: {}", student.name, if student.present { "Present" } else { "Absent" });
        }
    }
}

fn main() {
    let mut attendance = AttendanceList::new();
