#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <string.h>

typedef struct Task {
    int task_id;
    int priority;
    struct Task* next;
} Task;

static Task* scheduler_head = NULL;

bool task_exists(int task_id) {
    Task* current = scheduler_head;
    while (current != NULL) {
        if (current->task_id == task_id) return true;
        current = current->next;
    }
    return false;
}

void add_task(int task_id, int priority) {
    if (task_exists(task_id)) {
        fprintf(stderr, "Error: Task ID %d already exists.\n", task_id);
        return;
    }
    Task* new_task = malloc(sizeof(Task));
    if (new_task == NULL) {
        fprintf(stderr, "Error: Memory allocation failed.\n");
        exit(EXIT_FAILURE);
    }
    new_task->task_id = task_id;
    new_task->priority = priority;
    new_task->next = scheduler_head;
    scheduler_head = new_task;
}

void remove_task(int task_id) {
    Task* current = scheduler_head;
    Task* prev = NULL;
    while (current != NULL && current->task_id != task_id) {
        prev = current;
        current = current->next;
    }
    if (current == NULL) {
        fprintf(stderr, "Error: Task ID %d does not exist.\n", task_id);
        return;
    }
    if (prev == NULL) scheduler_head = current->next;
    else prev->next = current->next;
    free(current);
}

void change_priority(int task_id, int new_priority) {
    Task* current = scheduler_head;
    while (current != NULL) {
        if (current->task_id == task_id) {
            current->priority = new_priority;
            return;
        }
        current = current->next;
    }
    fprintf(stderr, "Error: Task ID %d does not exist.\n", task_id);
}

Task* fetch_next_task() {
    if (scheduler_head == NULL) {
        fprintf(stderr, "Error: No tasks to fetch.\n");
        return NULL;
    }
    Task* max_node = scheduler_head;
    Task* prev_max = NULL;
    Task* current = scheduler_head->next;
    Task* prev_current = scheduler_head;

    while (current != NULL) {
        if (current->priority > max_node->priority || 
            (current->priority == max_node->priority && current->task_id < max_node->task_id)) {
            max_node = current;
            prev_max = prev_current;
        }
        prev_current = current;
        current = current->next;
    }
    if (prev_max == NULL) scheduler_head = max_node->next;
    else prev_max->next = max_node->next;
    max_node->next = NULL;
    return max_node;
}

int main() {
    char line[256];
    while (fgets(line, sizeof(line), stdin)) {
        char* cmd = strtok(line, " \n");
        if (!cmd) continue;

        if (strcmp(cmd, "ADD_TASK") == 0) {
            char* id_str = strtok(NULL, " ");
            char* pri_str = strtok(NULL, " \n");
            if (!id_str || !pri_str) {
                fprintf(stderr, "Error: Invalid ADD_TASK command.\n");
                continue;
            }
            int id = atoi(id_str);
            int pri = atoi(pri_str);
            add_task(id, pri);
        } else if (strcmp(cmd, "REMOVE_TASK") == 0) {
            char* id_str = strtok(NULL, " \n");
            if (!id_str) {
                fprintf(stderr, "Error: Invalid REMOVE_TASK command.\n");
                continue;
            }
            remove_task(atoi(id_str));
        } else if (strcmp(cmd, "CHANGE_PRIORITY") == 0) {
            char* id_str = strtok(NULL, " ");
            char* pri_str = strtok(NULL, " \n");
            if (!id_str || !pri_str) {
                fprintf(stderr, "Error: Invalid CHANGE_PRIORITY command.\n");
                continue;
            }
            change_priority(atoi(id_str), atoi(pri_str));
        } else if (strcmp(cmd, "FETCH_NEXT_TASK") == 0) {
            Task* task = fetch_next_task();
            if (task) {
                printf("Task %d with priority %d fetched.\n", task->task_id, task->priority);
                free(task);
            }
        } else {
            fprintf(stderr, "Error: Unknown command '%s'.\n", cmd);
        }
    }

    while (scheduler_head) {
        Task* temp = scheduler_head;
        scheduler_head = scheduler_head->next;
        free(temp);
    }
    return 0;
}
