function calculateTimeSpan(startTimeStamp, endTimeStamp) {
    const startDate = new Date(startTimeStamp);
    const endDate = new Date(endTimeStamp);
    let years, months, days, hours, minutes, seconds;
    const secondsPerMinute = 60;
    const minutesPerHour = 60;
    const hoursPerDay = 24;

    if (isNaN(startDate.getTime()) || isNaN(endDate.getTime())) {
        throw new Error('Invalid timestamps provided');
    }

    if (endDate < startDate) {
        throw new Error('End timestamp is earlier than start timestamp');
    }

    years = endDate.getFullYear() - startDate.getFullYear();
    months = endDate.getMonth() - startDate.getMonth();
    days = endDate.getDate() - startDate.getDate();
    hours = endDate.getHours() - startDate.getHours();
    minutes = endDate.getMinutes() - startDate.getMinutes();
    seconds = endDate.getSeconds() - startDate.getSeconds();

    if (seconds < 0) {
        seconds += secondsPerMinute;
        minutes--;
    }

    if (minutes < 0) {
        minutes += minutesPerHour;
        hours--;
    }

    if (hours < 0) {
        hours += hoursPerDay;
        days--;
    }

    if (days < 0) {
        const tempDate = new Date(endDate);
        tempDate.setMonth(endDate.getMonth() - 1);
        tempDate.setDate(0);
        days += tempDate.getDate();
        months--;
    }

    if (months < 0) {
        months += 12;
        years--;
    }

    const parts = [];
    if (years > 0) parts.push(`${years} year${years !== 1 ? 's' : ''}`);
    if (months > 0) parts.push(`${months} month${months !== 1 ? 's' : ''}`);
    if (days > 0) parts.push(`${days} day${days !== 1 ? 's' : ''}`);
    if (hours > 0) parts.push(`${hours} hour${hours !== 1 ? 's' : ''}`);
    if (minutes > 0) parts.push(`${minutes} minute${minutes !== 1 ? 's' : ''}`);
    if (seconds > 0) parts.push(`${seconds} second${seconds !== 1 ? 's' : ''}`);

    if (parts.length === 0) return '0 seconds';

    return parts.reduce((acc, part, index) => 
        index === 0 ? part : 
        index === parts.length - 1 ? `${acc} and ${part}` : 
        `${acc}, ${part}`, '');
}
