using namespace std;

class Flight {
public:
    bool addPassenger(const string& name) {
        if (passengers.find(name) != passengers.end()) return false;
        passengers.insert(name);
        return true;
    }

    bool removePassenger(const string& name) {
        auto it = passengers.find(name);
        if (it == passengers.end()) return false;
        passengers.erase(it);
        return true;
    }

    size_t getPassengerCount() const {
        return passengers.size();
    }

    vector<string> getPassengerList() const {
        return vector<string>(passengers.begin(), passengers.end());
    }

private:
    set<string> passengers;
};

class ReservationSystem {
public:
    void book(const string& flightID, const string& passengerName) {
        bool success = flights[flightID].addPassenger(passengerName);
        if (success) {
            cout << "Booked " << passengerName << " on flight " << flightID << ".\n";
        } else {
            cout << "Passenger " << passengerName << " is already booked on flight " << flightID << ".\n";
        }
    }

    void cancel(const string& flightID, const string& passengerName) {
        auto it = flights.find(flightID);
        if (it == flights.end()) {
            cout << "Flight " << flightID << " does not exist.\n";
            return;
        }
        bool success = it->second.removePassenger(passengerName);
        if (success) {
            cout << "Canceled booking for " << passengerName << " on flight " << flightID << ".\n";
        } else {
            cout << "Passenger " << passengerName << " not found on flight " << flightID << ".\n";
        }
    }

    void listFlights() const {
        if (flights.empty()) {
            cout << "No flights scheduled.\n";
            return;
        }
        for (const auto& pair : flights) {
            cout << "Flight " << pair.first << ": " << pair.second.getPassengerCount() << " passengers\n";
        }
    }

    void listPassengers(const string& flightID) const {
        auto it = flights.find(flightID);
        if (it == flights.end()) {
            cout << "Flight " << flightID << " does not exist.\n";
            return;
        }
        vector<string> passengers = it->second.getPassengerList();
        if (passengers.empty()) {
            cout << "No passengers booked on flight " << flightID << ".\n";
        } else {
            cout << "Passengers on flight " << flightID << ":\n";
            for (const auto& name : passengers) {
                cout << "- " << name << "\n";
            }
        }
    }

private:
    map<string, Flight> flights;
};

int main() {
    ReservationSystem reservationSystem;
    string line;

    while (getline(cin, line)) {
        istringstream iss(line);
        vector<string> tokens;
        string token;
        while (iss >> token) tokens.push_back(token);
        if (tokens.empty()) continue;

        string command = tokens[0];

        if (command == "BOOK") {
            if (tokens.size() < 3) {
                cout << "Invalid BOOK command. Usage: BOOK flightID passengerName\n";
                continue;
            }
            string flightID = tokens[1];
            string passengerName;
            for (size_t i = 2; i < tokens.size(); ++i) {
                if (i > 2) passengerName += " ";
                passengerName += tokens[i];
            }
            reservationSystem.book(flightID, passengerName);
        } else if (command == "CANCEL") {
            if (tokens.size() < 3) {
                cout << "Invalid CANCEL command. Usage: CANCEL flightID passengerName\n";
                continue;
            }
            string flightID = tokens[1];
            string passengerName;
            for (size_t i = 2; i < tokens.size(); ++i) {
                if (i > 2) passengerName += " ";
                passengerName += tokens[i];
            }
            reservationSystem.cancel(flightID, passengerName);
        } else if (command == "FLIGHT_LIST") {
            reservationSystem.listFlights();
        } else if (command == "PASSENGER_LIST") {
            if (tokens.size() < 2) {
                cout << "Invalid PASSENGER_LIST command. Usage: PASSENGER_LIST flightID\n";
                continue;
            }
            string flightID = tokens[1];
            reservationSystem.listPassengers(flightID);
        } else {
            cout << "Unknown command: " << command << "\n";
        }
    }

    return 0;
}
