import java.util.HashSet;
import java.util.Set;

public class ParkingGarage {
    private int totalSpaces;
    private int availableSpaces;
    private Set<String> parkedVehicles;

    public ParkingGarage(int totalSpaces) {
        this.totalSpaces = totalSpaces;
        this.availableSpaces = totalSpaces;
        this.parkedVehicles = new HashSet<>();
    }

    public String parkVehicle(String licensePlate) throws Exception {
        if (availableSpaces == 0) {
            return "No spots available.";
        }
        if (parkedVehicles.contains(licensePlate)) {
            throw new Exception("Vehicle already parked.");
        }
        parkedVehicles.add(licensePlate);
        availableSpaces--;
        return "Vehicle parked successfully.";
    }

    public void departVehicle(String licensePlate) throws Exception {
        if (!parkedVehicles.contains(licensePlate)) {
            throw new Exception("Vehicle not found.");
        }
        parkedVehicles.remove(licensePlate);
        availableSpaces++;
    }

    public int countAvailableSpaces() {
        return availableSpaces;
    }
}
