from typing import Union, List, Dict

def compute_volatility(price_data: List[float]) -> Union[float, str]:
    returns: List[float] = []
    mean_return: float = 0.0
    squared_diffs: List[float] = []
    variance: float = 0.0
    std_dev: float = 0.0
    annualized_volatility: float = 0.0

    if not price_data or len(price_data) < 2:
        return "Error: Insufficient data points for volatility calculation."

    for price in price_data:
        if not isinstance(price, (int, float)):
            return "Error: Non-numeric value found in price data."

    for i in range(1, len(price_data)):
        daily_return: float = (price_data[i] - price_data[i-1]) / price_data[i-1]
        returns.append(daily_return)

    mean_return = sum(returns) / len(returns)
    squared_diffs = [(r - mean_return) ** 2 for r in returns]
    variance = sum(squared_diffs) / len(returns)
    std_dev = variance ** 0.5
    annualized_volatility = std_dev * (252 ** 0.5)

    return annualized_volatility

def evaluate_risk(profile: Dict, financial_products: List[Dict]) -> str:
    risk_assessment: str = ""
    portfolio_volatility: float = 0.0
    total_volatility: float = 0.0
    product_count: int = 0
    error_message: str = ""

    if not profile or not isinstance(profile, dict):
        return "Error: Invalid profile."
    if not financial_products:
        return "Error: No financial products provided."
    if 'risk_tolerance' not in profile:
        return "Error: Profile missing 'risk_tolerance' key."

    for product in financial_products:
        if 'volatility' not in product or not isinstance(product['volatility'], (int, float)):
            return "Error: Invalid or missing 'volatility' in financial product."
        total_volatility += product['volatility']
        product_count += 1

    portfolio_volatility = total_volatility / product_count

    risk_tolerance = profile['risk_tolerance']
    if risk_tolerance == 'low':
        if portfolio_volatility <= 0.1:
            risk_assessment = 'Low'
        elif portfolio_volatility <= 0.2:
            risk_assessment = 'Moderate'
        else:
            risk_assessment = 'High'
    elif risk_tolerance == 'medium':
        if portfolio_volatility <= 0.15:
            risk_assessment = 'Low'
        elif portfolio_volatility <= 0.25:
            risk_assessment = 'Moderate'
        else:
            risk_assessment = 'High'
    elif risk_tolerance == 'high':
        if portfolio_volatility <= 0.2:
            risk_assessment = 'Low'
        elif portfolio_volatility <= 0.3:
            risk_assessment = 'Moderate'
        else:
            risk_assessment = 'High'
    else:
        return "Error: Invalid risk tolerance in profile."

    return risk_assessment
