import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import java.util.concurrent.ConcurrentHashMap;

@RestController
public class ProfileController {

    private final ConcurrentHashMap<String, UserProfile> userProfiles = new ConcurrentHashMap<>();

    @PostMapping("/profiles")
    public ResponseEntity<Void> createProfile(@RequestBody UserProfile userProfile) {
        userProfiles.put(userProfile.getUsername(), userProfile);
        return ResponseEntity.status(HttpStatus.CREATED).build();
    }

    @GetMapping("/profile/{username}")
    public ResponseEntity<UserProfile> getProfile(@PathVariable String username) {
        UserProfile profile = userProfiles.get(username);
        if (profile == null) {
            return ResponseEntity.status(HttpStatus.NOT_FOUND).build();
        }
        return ResponseEntity.ok(profile);
    }

    @PutMapping("/profile/{username}")
    public ResponseEntity<Void> updateProfile(@PathVariable String username, @RequestBody UpdateProfileRequest updateRequest) {
        UserProfile profile = userProfiles.get(username);
        if (profile == null) {
            return ResponseEntity.status(HttpStatus.NOT_FOUND).build();
        }
        profile.setEmail(updateRequest.getEmail());
        profile.setAge(updateRequest.getAge());
        userProfiles.put(username, profile);
        return ResponseEntity.ok().build();
    }

    @DeleteMapping("/profile/{username}")
    public ResponseEntity<Void> deleteProfile(@PathVariable String username) {
        if (!userProfiles.containsKey(username)) {
            return ResponseEntity.status(HttpStatus.NOT_FOUND).build();
        }
        userProfiles.remove(username);
        return ResponseEntity.status(HttpStatus.NO_CONTENT).build();
    }

    public static class UserProfile {
        private String username;
        private String email;
        private int age;

        public UserProfile() {}

        public UserProfile(String username, String email, int age) {
            this.username = username;
            this.email = email;
            this.age = age;
        }

        public String getUsername() { return username; }
        public void setUsername(String username) { this.username = username; }
        public String getEmail() { return email; }
        public void setEmail(String email) { this.email = email; }
        public int getAge() { return age; }
        public void setAge(int age) { this.age = age; }
