#include <stdexcept>

class Stack {
private:
    struct Node {
        int data;
        Node* next;
        Node(int value) : data(value), next(nullptr) {}
    };
    Node* topNode;
    int itemCount;

public:
    Stack() : topNode(nullptr), itemCount(0) {}
    ~Stack() {
        Node* currentNode = topNode;
        while (currentNode != nullptr) {
            Node* nextNode = currentNode->next;
            delete currentNode;
            currentNode = nextNode;
        }
    }

    void push(int value) {
        Node* newNode = new Node(value);
        newNode->next = topNode;
        topNode = newNode;
        itemCount++;
    }

    void pop() {
        if (isEmpty()) {
            throw std::underflow_error("Stack is empty");
        }
        Node* tempNode = topNode;
        topNode = topNode->next;
        delete tempNode;
        itemCount--;
    }

    int peek() const {
        if (isEmpty()) {
            throw std::underflow_error("Stack is empty");
        }
        return topNode->data;
    }

    int size() const {
        return itemCount;
    }

    bool isEmpty() const {
        return (topNode == nullptr);
    }
};
