let currentTokens = MAX_CALLS_PER_MINUTE;
let lastRefillTimestamp = Date.now();

function isApiCallAllowed() {
    const currentTimestamp = Date.now();
    const timeElapsed = currentTimestamp - lastRefillTimestamp;
    const tokensToAdd = (timeElapsed * MAX_CALLS_PER_MINUTE) / MILLISECONDS_PER_MINUTE;

    if (tokensToAdd > 0) {
        currentTokens = Math.min(currentTokens + tokensToAdd, MAX_CALLS_PER_MINUTE);
        lastRefillTimestamp = currentTimestamp;
    }

    if (currentTokens >= 1) {
        currentTokens -= 1;
        return true;
    }

    return false;
