#include <iostream>
#include <string>
#include <unordered_map>
#include <mutex>
#include <sstream>
#include <algorithm>

using namespace std;

unordered_map<string, string> database;
mutex db_mutex;

void handle_SET(const string& key, const string& value) {
    lock_guard<mutex> lock(db_mutex);
    database[key] = value;
}

string handle_GET(const string& key) {
    lock_guard<mutex> lock(db_mutex);
    auto it = database.find(key);
    if (it == database.end()) {
        return "Key not found";
    }
    return it->second;
}

string handle_DELETE(const string& key) {
    lock_guard<mutex> lock(db_mutex);
    auto it = database.find(key);
    if (it == database.end()) {
        return "Key not found";
    }
    database.erase(it);
    return "";
}

string handle_UPDATE(const string& key, const string& value) {
    lock_guard<mutex> lock(db_mutex);
    auto it = database.find(key);
    if (it == database.end()) {
        return "Key not found";
    }
    database[key] = value;
    return "";
}

int main() {
    string line;
    while (getline(cin, line)) {
        istringstream iss(line);
        string command, key, value;
        iss >> command;

        if (command == "SET") {
            iss >> key;
            getline(iss, value);
            if (!value.empty()) {
                value.erase(0, 1);
            }
            handle_SET(key, value);
        } else if (command == "GET") {
            iss >> key;
            cout << handle_GET(key) << endl;
        } else if (command == "DELETE") {
            iss >> key;
            string result = handle_DELETE(key);
            if (!result.empty()) {
                cout << result << endl;
            }
        } else if (command == "UPDATE") {
            iss >> key;
            getline(iss, value);
            if (!value.empty()) {
                value.erase(0, 1);
            }
            string result = handle_UPDATE(key, value);
            if (!result.empty()) {
                cout << result << endl;
            }
        } else {
            cout << "Invalid command" << endl;
        }
    }
    return 0;
}
